SELECT COUNT(event_id) AS event_count
FROM seismic_events
WHERE station_id = 1;

SELECT COUNT(station_id) AS active_station_count
FROM seismic_stations
WHERE station_status = 'active';

SELECT DISTINCT u.user_name
FROM access_logs al
INNER JOIN users u ON al.user_id = u.user_id;

SELECT file_size
FROM data_files
WHERE file_size > 1.0;

SELECT station_status, COUNT(station_id) AS station_count
FROM seismic_stations
GROUP BY station_status;

SELECT COUNT(*) AS active_station_count
FROM seismic_stations
WHERE station_status = 'active';

SELECT type, COUNT(*) AS event_count
FROM seismic_events
GROUP BY type;

SELECT station_name
FROM seismic_stations
WHERE station_id = 1;
